  def lucide_icon(name, css: "h-5 w-5", title: nil)
    path = ICONS.fetch(name.to_sym)
    title_markup = title.present? ? tag.title(title) : "".html_safe
    tag.svg(title_markup + path.html_safe, xmlns: "http://www.w3.org/2000/svg", viewBox: "0 0 24 24", fill: "none", stroke: "currentColor", "stroke-width": 2, "stroke-linecap": "round", "stroke-linejoin": "round", class: css, "aria-hidden": title.blank?)
  end
